import React, { useEffect } from "react";
import axios from "axios";
import { startTracking, getData } from "./tracker";

function ColorGame({ onNext }) {

  useEffect(() => {
    startTracking();
  }, []);

  const handleDrop = async (correct) => {
    if (correct) {
      alert("Correct ✅");
    } else {
      alert("Wrong ❌");
    }

    const data = getData();

    try {
      await axios.post("http://localhost:5000/save", {
        activity: "color_game",
        ...data,
      });
    } catch (err) {
      console.error("ColorGame save failed:", err);
      alert("Progress could not be saved to the server.");
    }
  };

  return (
    <div style={{ textAlign: "center", paddingTop: "50px", background: "#FFFACD", height: "100vh" }}>
      <h1>Match Colors 🌈</h1>

      {/* 🔴 RED ITEM */}
      <div
        draggable
        onDragStart={(e) => e.dataTransfer.setData("color", "red")}
        style={{
          fontSize: "40px",
          margin: "20px",
          cursor: "grab",
        }}
      >
        🔴
      </div>

      {/* 🔵 BLUE ITEM */}
      <div
        draggable
        onDragStart={(e) => e.dataTransfer.setData("color", "blue")}
        style={{
          fontSize: "40px",
          margin: "20px",
          cursor: "grab",
        }}
      >
        🔵
      </div>

      {/* 🎯 RED DROP BOX */}
      <div
        onDragOver={(e) => e.preventDefault()}
        onDrop={(e) => {
          const color = e.dataTransfer.getData("color");
          handleDrop(color === "red");
        }}
        style={{
          width: "150px",
          height: "150px",
          backgroundColor: "#FFB6C1",
          margin: "20px auto",
          lineHeight: "150px",
        }}
      >
        Red Box
      </div>

      {/* 🎯 BLUE DROP BOX */}
      <div
        onDragOver={(e) => e.preventDefault()}
        onDrop={(e) => {
          const color = e.dataTransfer.getData("color");
          handleDrop(color === "blue");
        }}
        style={{
          width: "150px",
          height: "150px",
          backgroundColor: "#ADD8E6",
          margin: "20px auto",
          lineHeight: "150px",
        }}
      >
        Blue Box
      </div>

      <button
        onClick={() => onNext && onNext()}
        style={{ fontSize: "20px", marginTop: "20px" }}
      >
        Restart 🎮
      </button>
    </div>
  );
}

export default ColorGame;
